import WidgetKit
import SwiftUI
import AppIntents

struct BatteryLevelProvider: AppIntentTimelineProvider {
    func placeholder(in context: Context) -> BatteryLevelEntry {
        BatteryLevelEntry(date: Date(), level: 100)
    }
    func snapshot(for configuration: ConfigurationAppIntent, in context: Context) async -> BatteryLevelEntry {
        BatteryLevelEntry(date: Date(), level: 75)
    }
    func timeline(for configuration: ConfigurationAppIntent, in context: Context) async -> Timeline<BatteryLevelEntry> {
        let entry = BatteryLevelEntry(date: Date(), level: UIDevice.current.batteryLevel)
        return Timeline(entries: [entry], policy: .atEnd)
    }
}

struct BatteryLevelEntry: TimelineEntry {
    let date: Date
    let level: Float
}

struct BatteryLevelWidgetEntryView: View {
    var entry: BatteryLevelProvider.Entry
    var body: some View {
        VStack {
            Text("Battery")
            Text("\(Int(entry.level * 100))%")
                .font(.largeTitle)
        }
    }
}

@main
struct BatteryLevelWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(kind: "BatteryLevelWidget", intent: ConfigurationAppIntent.self, provider: BatteryLevelProvider()) { entry in
            BatteryLevelWidgetEntryView(entry: entry)
        }
        .configurationDisplayName("Battery Level")
        .description("Shows the current battery level.")
        .supportedFamilies([.accessoryRectangular, .accessoryInline, .accessoryCircular, .systemSmall])
    }
}

import SwiftUI

@Observable
class CounterModel {
    var count: Int = 0
    func increment() {
        count += 1
    }
}

struct ContentView: View {
    @State var model = CounterModel()
    var body: some View {
        VStack {
            Text("Count: \ (model.count)")
            Button("Increment") {
                model.increment()
            }
        }
    }
}

import SwiftUI
import RealityKit

struct SpinningCubeImmersiveSpace: View {
    var body: some View {
        RealityView { content in
            let box = ModelEntity(mesh: .generateBox(size: 0.2))
            box.transform.rotation = simd_quatf(angle: .pi / 4, axis: [0, 1, 0])
            content.add(box)
        } update: { content in
            if let box = content.entities.first {
                box.transform.rotation *= simd_quatf(angle: 0.01, axis: [0, 1, 0])
            }
        }
    }
}

