import SwiftUI

@Observable
class WorkoutTimer {
    var seconds: Int = 0
    var isRunning: Bool = false
    func start() {
        isRunning = true
    }
    func stop() {
        isRunning = false
    }
}

struct TimerView: View {
    @State var timer = WorkoutTimer()
    var body: some View {
        VStack {
            Text("Seconds: \ (timer.seconds)")
            Button(timer.isRunning ? "Stop" : "Start") {
                timer.isRunning ? timer.stop() : timer.start()
            }
        }
    }
}
